// Cron Match? (Function) —— OR 语义 + 透传 + 不拦截（仅输出 cron_ok）
// 读取：cron（5或6段都行）、timezone（如 Asia/Tokyo）
// 输出：原样透传所有字段 + { cron_ok, now_debug, cron_parts }

function nowPartsInTZ(tz) {
  const fmt = new Intl.DateTimeFormat('en-GB', {
    timeZone: tz, weekday:'short',
    year:'numeric', month:'2-digit', day:'2-digit',
    hour:'2-digit', minute:'2-digit', second:'2-digit',
    hour12:false
  });
  const p = fmt.formatToParts(new Date());
  const get = (t) => parseInt(p.find(x => x.type === t).value, 10);
  const wShort = p.find(x => x.type === 'weekday').value; // Sun..Sat
  const dowMap = {Sun:0,Mon:1,Tue:2,Wed:3,Thu:4,Fri:5,Sat:6};
  return {
    sec: get('second'),
    min: get('minute'),
    hour: get('hour'),
    dom: get('day'),
    mon: get('month'),
    dow: dowMap[wShort],
    wShort
  };
}

function normalizeDowExpr(expr) {
  // 支持英文星期：MON..SUN（不区分大小写）
  const map = {SUN:0,MON:1,TUE:2,WED:3,THU:4,FRI:5,SAT:6};
  return String(expr).toUpperCase().replace(/[A-Z]{3}/g, (m) => {
    if (map.hasOwnProperty(m)) return String(map[m]);
    return m;
  }).replace(/\b7\b/g, '0'); // 7当周日
}

function matchPart(val, expr) {
  const s = String(expr).trim();
  if (s === '*') return true;
  const tokens = s.split(',');
  for (const t of tokens) {
    if (t === '*') return true;
    if (t.startsWith('*/')) {
      const step = parseInt(t.slice(2), 10) || 1;
      if (val % step === 0) return true;
      continue;
    }
    if (t.includes('-')) {
      const [a, b] = t.split('-').map(n => parseInt(n, 10));
      if (val >= a && val <= b) return true;
      continue;
    }
    if (val === parseInt(t, 10)) return true;
  }
  return false;
}

const cron = String($json.cron || '').trim();
const tz = String($json.timezone || 'Asia/Tokyo');

let cron_ok = true; // 未配置 cron 时视为放行
let parts_used = null;
let now_dbg = null;

if (cron) {
  const parts = cron.split(/\s+/).filter(Boolean);
  const hasSec = parts.length === 6;
  if (!(parts.length === 5 || parts.length === 6)) {
    cron_ok = false;
  } else {
    const [secE, minE, hourE, domE, monE, dowE] = hasSec
      ? [parts[0], parts[1], parts[2], parts[3], parts[4], parts[5]]
      : ['*', parts[0], parts[1], parts[2], parts[3], parts[4]];

    const now = nowPartsInTZ(tz);
    now_dbg = { tz, ...now };

    const secOk  = matchPart(now.sec,  secE);
    const minOk  = matchPart(now.min,  minE);
    const hourOk = matchPart(now.hour, hourE);
    const monOk  = matchPart(now.mon,  monE);

    // ---- 关键：DOM/DOW 的 OR 语义 ----
    const domStar = String(domE).trim() === '*';
    const dowExpr = normalizeDowExpr(dowE);
    const dowStar = String(dowExpr).trim() === '*';
    const domOk   = matchPart(now.dom, domE);
    const dowOk   = matchPart(now.dow, dowExpr);

    // Vixie cron 语义：
    // 若 DOM 与 DOW 同时不是 * → 二者采用 OR（任一为真即命中）
    // 否则（其中一个是 *） → 要求另一个匹配
    let dayOk;
    if (!domStar && !dowStar) dayOk = (domOk || dowOk);
    else if (!domStar)        dayOk = domOk;
    else if (!dowStar)        dayOk = dowOk;
    else                      dayOk = true;

    cron_ok = secOk && minOk && hourOk && monOk && dayOk;
    parts_used = { secE, minE, hourE, domE, monE, dowE: dowExpr };
  }
}

return [
  {
    json: {
      ...$json,         // 透传所有上游字段
      cron_ok,
      now_debug: now_dbg,
      cron_parts: parts_used
    }
  }
];

/**
 * Cron Gate (Function) — 顶层拦截
 * 读取上游 Set 的 $json.cron / $json.timezone
 * 5 或 6 段 cron；DOM/DOW 采用 OR 语义；支持 MON..SUN 名称；支持 步长、范围、列表。
 * 匹配失败 → return [] 直接阻断后续节点。
 */

function matchPart(v, expr) {
  const s = String(expr || '').trim();
  if (s === '*') return true;
  const items = s.split(',');
  for (let i = 0; i < items.length; i++) {
    const t = items[i].trim();
    if (t === '*') return true;
    if (t.startsWith('*/')) { const step = parseInt(t.slice(2), 10) || 1; if ((v % step) === 0) return true; continue; }
    if (t.includes('-')) { const ab = t.split('-'); const a = parseInt(ab[0],10), b = parseInt(ab[1],10); if (v >= a && v <= b) return true; continue; }
    if (v === parseInt(t,10)) return true;
  }
  return false;
}

function cronMatchNow(cron, tz) {
  const tokens = String(cron || '').trim().split(/\s+/).filter(Boolean);
  if (!(tokens.length === 5 || tokens.length === 6)) return false;

  // 当前时间（按 tz）
  const fmt = new Intl.DateTimeFormat('en-GB', {
    timeZone: tz || 'Asia/Shanghai',
    weekday: 'short', year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
  });
  const parts = fmt.formatToParts(new Date());
  const get = (t) => parseInt(parts.find(x => x.type === t).value, 10);
  const sec  = get('second');
  const min  = get('minute');
  const hour = get('hour');
  const day  = get('day');
  const mon  = get('month');
  const mapW = { Sun:0, Mon:1, Tue:2, Wed:3, Thu:4, Fri:5, Sat:6 };
  const dow  = mapW[parts.find(x => x.type === 'weekday').value];

  const hasSec = tokens.length === 6;
  const [secE, minE, hourE, domE, monE, dowE0] = hasSec ? tokens : ['*', tokens[0], tokens[1], tokens[2], tokens[3], tokens[4]];

  const dowE = String(dowE0).toUpperCase()
    .replace(/\bSUN\b/g,'0').replace(/\bMON\b/g,'1').replace(/\bTUE\b/g,'2')
    .replace(/\bWED\b/g,'3').replace(/\bTHU\b/g,'4').replace(/\bFRI\b/g,'5')
    .replace(/\bSAT\b/g,'6').replace(/\b7\b/g,'0');

  const secOk  = matchPart(sec,  secE);
  const minOk  = matchPart(min,  minE);
  const hourOk = matchPart(hour, hourE);
  const monOk  = matchPart(mon,  monE);
  const domOk  = matchPart(day,  domE);
  const dowOk  = matchPart(dow,  dowE);

  // DOM 与 DOW 采用 OR 语义（标准 crontab 行为）
  const domStar = String(domE).trim() === '*';
  const dowStar = String(dowE).trim() === '*';
  let dayOk;
  if (!domStar && !dowStar) dayOk = domOk || dowOk;
  else if (!domStar)        dayOk = domOk;
  else if (!dowStar)        dayOk = dowOk;
  else                      dayOk = true;

  return secOk && minOk && hourOk && monOk && dayOk;
}

// ====== 从上游 Set 读取 cron/timezone ======
const cron = String($json.cron || '').trim();
const tz   = String($json.timezone || 'Asia/Shanghai').trim();

// 严格模式：未配置 cron 就直接阻断，避免误发（如需放行，把 STRICT 改为 false）
const STRICT = true;
if (!cron) {
  if (STRICT) return [];      // 顶层 early return：阻断
  // 非严格可放行：return [{ json: $json }];
}

// 命中才放行；不命中直接阻断
if (!cronMatchNow(cron, tz)) {
  return [];                  // 顶层 early return：阻断
}

// 通过 → 透传当前数据给后续节点
return [{ json: $json }];

// === Save Workday Cache (Code) ===
// 把“今天的 t”写回 __cnDayTypes[ymd]，写 __cnDayMeta[ymd].fetchedAt，
// 并写全局 __cnLastFetchedAt（兜底），返回 cache_debug。

function getStatic(scope='global'){
  try {
    return typeof $getWorkflowStaticData === 'function'
      ? $getWorkflowStaticData(scope)
      : (this && this.getWorkflowStaticData ? this.getWorkflowStaticData(scope) : {});
  } catch { return {}; }
}
function ymdInTZ(d, tz='Asia/Shanghai'){
  return new Intl.DateTimeFormat('sv-SE', {
    timeZone: tz, year:'numeric', month:'2-digit', day:'2-digit'
  }).format(d);
}
function isWeekendCN(d=new Date()){
  const w = new Intl.DateTimeFormat('en-GB', { timeZone: 'Asia/Shanghai', weekday:'short' }).format(d);
  return (w === 'Sat' || w === 'Sun');
}
function readItemsJson(name) {
  const arr = $items(name) || [];
  return (arr[0] && arr[0].json) ? arr[0].json : null;
}

const sd = getStatic('global');
sd.__cnDayTypes = sd.__cnDayTypes || {}; // { 'YYYY-MM-DD': 0/1/2/3 }
sd.__cnDayMeta  = sd.__cnDayMeta  || {}; // { 'YYYY-MM-DD': { fetchedAt } }
sd.__cnYearMeta = sd.__cnYearMeta || {}; // { 'YYYY': { fetchedAt } }
sd.__cnLastFetchedAt = sd.__cnLastFetchedAt || 0;

const nowTs = Date.now();
const ymd = $json.today_ymd || ymdInTZ(new Date());
const year = String($json.today_year || '').trim();
const nextYear = String($json.next_year || '').trim();

// 兼容 3 种名字（— / - / 空格）
const yJson  = readItemsJson('Holiday CN (Y) – HTTP') || readItemsJson('Holiday CN (Y) - HTTP') || readItemsJson('Holiday CN (Y) HTTP');
const y1Json = readItemsJson('Holiday CN (Y+1) – HTTP') || readItemsJson('Holiday CN (Y+1) - HTTP') || readItemsJson('Holiday CN (Y+1) HTTP');

function writeYear(yearStr, data){
  if (!data || !Array.isArray(data.days)) return;
  for (let i=0; i<data.days.length; i++){
    const d = data.days[i];
    const day = String(d.date || '').trim();
    if (!/^\d{4}-\d{2}-\d{2}$/.test(day)) continue;
    // isOffDay: true=2(节休)，false=3(调休上班)
    sd.__cnDayTypes[day] = (d.isOffDay ? 2 : 3);
  }
  if (yearStr) sd.__cnYearMeta[yearStr] = { fetchedAt: nowTs };
}

if (yJson)  writeYear(year,     yJson);
if (y1Json) writeYear(nextYear, y1Json);

// 计算今天类型，年表没覆盖则按周末=1/工作日=0
let t = sd.__cnDayTypes[ymd];
if (typeof t === 'undefined') t = isWeekendCN(new Date()) ? 1 : 0;

// ★写今天的类型 & meta & 全局 lastFetchedAt
sd.__cnDayTypes[ymd] = t;
sd.__cnDayMeta[ymd]  = { fetchedAt: nowTs };
sd.__cnLastFetchedAt = nowTs;

// 可选：清理历史（~800天）
(function prune(){
  const keys = Object.keys(sd.__cnDayTypes).sort();
  const cutoff = ymdInTZ(new Date(Date.now() - 800*24*3600*1000));
  for (const k of keys) if (k < cutoff) delete sd.__cnDayTypes[k];
})();

return [{
  json: {
    ...$json,
    today_type: t,
    sd,
    cache_debug: {
      ymd,
      years_cached: Object.keys(sd.__cnYearMeta || {}),
      dayTypes_count: Object.keys(sd.__cnDayTypes || {}).length,
      today_meta: sd.__cnDayMeta ? sd.__cnDayMeta[ymd] : null,
      last_fetched_at: sd.__cnLastFetchedAt || null,
      got_Y:  !!(yJson && Array.isArray(yJson.days)),
      got_Y1: !!(y1Json && Array.isArray(y1Json.days))
    }
  }
}];

const crypto = require('crypto');
function signUrl(base, secret) {
  let url = String(base || '').trim();
  const sec = String(secret || '').trim();
  if (!sec) return url;
  const ts = Date.now();
  const sign = encodeURIComponent(crypto.createHmac('sha256', sec).update(ts + '\n' + sec).digest('base64'));
  url += (url.includes('?') ? '&' : '?') + `timestamp=${ts}&sign=${sign}`;
  return url;
}
function parseJSON(str, defVal) { try { return JSON.parse(str); } catch { return defVal; } }
function ensureKeyword(text, kw) { const k = String(kw || '').trim(); return k && !text.includes(k) ? `${k}\n\n${text}` : text; }
function truthy(v){ return /^(1|true|yes|y)$/i.test(String(v || '').trim()); }
function cleanUrl(u) { let v = String(u || '').trim(); if (!v) return ''; if (!/^https?:\/\//i.test(v) && !/^dingtalk:\/\//i.test(v)) v = 'https://' + v.replace(/^\/+/, ''); v = v.replace(/ /g, '%20').replace(/\(/g, '%28').replace(/\)/g, '%29'); return v; }
function replacePlaceholders(text, map) {
  let out = String(text || '');
  for (const [k, v] of Object.entries(map)) {
    const s = String(v == null ? '' : v);
    out = out.replace(new RegExp(`\\{\\{\\s*${k}\\s*\\}\\}`, 'g'), s)
             .replace(new RegExp(`\\$\\{\\s*${k}\\s*\\}`, 'g'), s);
  }
  return out;
}
function dedent(md) {
  const lines = String(md || '').replace(/\r\n?/g, '\n').split('\n');
  const nonEmpty = lines.filter(l => l.trim().length);
  const indent = nonEmpty.length ? Math.min(...nonEmpty.map(l => (l.match(/^[ \t]*/)[0] || '').length)) : 0;
  return lines.map(l => l.slice(indent)).join('\n').trim();
}
function getFromSet(key, defVal) {
  const fromSet = ($items("Cron: Config (Set)")?.[0]?.json) || {};
  const v1 = $json[key]; if (v1 !== undefined && v1 !== null && String(v1) !== '') return v1;
  const v2 = fromSet[key]; if (v2 !== undefined && v2 !== null && String(v2) !== '') return v2;
  return defVal;
}
// ---- cron guard (OR semantics) ----
(function guardByCron(){
  const cron = String(getFromSet('cron','') || '').trim();
  if (!cron) return;
  const tz = String(getFromSet('timezone','Asia/Shanghai'));
  const fmt = new Intl.DateTimeFormat('en-GB', { timeZone: tz, weekday:'short', year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit', second:'2-digit', hour12:false });
  const p = fmt.formatToParts(new Date());
  const val = t => parseInt(p.find(x=>x.type===t).value, 10);
  const sec=val('second'), min=val('minute'), hour=val('hour'), day=val('day'), mon=val('month');
  const mapW={Sun:0,Mon:1,Tue:2,Wed:3,Thu:4,Fri:5,Sat:6}; const dow=mapW[p.find(x=>x.type==='weekday').value];
  function matchPart(v, expr){
    const tokens = String(expr).split(',');
    for (const t of tokens){
      if (t==='*') return true;
      if (t.startsWith('*/')) { const step=parseInt(t.slice(2),10)||1; if ((v) % step === 0) return true; continue; }
      if (t.includes('-')) { const [a,b]=t.split('-').map(n=>parseInt(n,10)); if (v>=a && v<=b) return true; continue; }
      const n = parseInt(t,10); if (v===n) return true;
    }
    return false;
  }
  const parts = cron.split(/\s+/).filter(Boolean);
  const hasSec = parts.length===6;
  const [secE,minE,hourE,domE,monE,dowE0] = hasSec ? parts : ['*',parts[0],parts[1],parts[2],parts[3],parts[4]];
  const dowE = String(dowE0).toUpperCase().replace(/\bSUN\b/g,'0').replace(/\bMON\b/g,'1').replace(/\bTUE\b/g,'2').replace(/\bWED\b/g,'3').replace(/\bTHU\b/g,'4').replace(/\bFRI\b/g,'5').replace(/\bSAT\b/g,'6').replace(/\b7\b/g,'0');
  const secOk  = matchPart(sec,secE);
  const minOk  = matchPart(min,minE);
  const hourOk = matchPart(hour,hourE);
  const monOk  = matchPart(mon,monE);
  const domOk  = matchPart(day,domE);
  const dowOk  = matchPart(dow,dowE);
  const domStar = String(domE).trim()==='*';
  const dowStar = String(dowE).trim()==='*';
