// ---- workday guard ----
const t = ($json.today_type !== undefined) ? $json.today_type : ($json.today_type_cached !== undefined ? $json.today_type_cached : undefined);
if (t === 1 || t === 2) return [];

// ---- build payload ----
const baseWebhook = getFromSet('dingtalk_webhook_url', '');
const secret      = getFromSet('dingtalk_secret', '');
const mdTitle     = getFromSet('md_title', '提交日志提醒');
const linkTitle   = getFromSet('link_title', '提交日志');
const linkUrl     = cleanUrl(getFromSet('link_url', ''));
const required    = getFromSet('required_keyword', '');
const atAll       = truthy(getFromSet('at_all', ''));
const atMobiles   = String(getFromSet('at_mobiles', '') || '').trim()
  ? String(getFromSet('at_mobiles')).split(',').map(s => s.trim()).filter(Boolean)
  : [];
const EMOJIS = parseJSON(getFromSet('random_emojis_json', ''), ["💡","📝","✨","⏰","✅","📌","🚀"]);
const QUOTES = parseJSON(getFromSet('random_quotes_json', ''), ["再小的进步也是进步。","把今天做到最好，明天自然会更好。","先完成，再完美。","复盘能让每一步都更值钱。","专注当下这一件事。"]);
const TIPS   = parseJSON(getFromSet('random_tips_json',   ''), ["用要点和小标题写日志，可读性更好。","同步 1 张关键截图，信息量翻倍。","记录 1 条风险+应对，让复盘更顺畅。","尽量量化结果：进度/耗时/影响。"]);
const pickOne = a => a && a.length ? a[Math.floor(Math.random()*a.length)] : '';
const rndEmoji = pickOne(EMOJIS), rndQuote = pickOne(QUOTES), rndTip = pickOne(TIPS);

const tzShow = getFromSet('timezone', 'Asia/Shanghai');
const nowDisp = new Date();
const dateStr = new Intl.DateTimeFormat('ja-JP', { timeZone: tzShow, year:'numeric', month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit' }).format(nowDisp);
let weekdayStr;
try { weekdayStr = new Intl.DateTimeFormat('zh-CN', { timeZone: tzShow, weekday:'long' }).format(nowDisp); }
catch {
  const w = new Intl.DateTimeFormat('en-GB', { timeZone: tzShow, weekday:'short' }).format(nowDisp);
  weekdayStr = ({Sun:'星期日',Mon:'星期一',Tue:'星期二',Wed:'星期三',Thu:'星期四',Fri:'星期五',Sat:'星期六'})[w] || w;
}

let md = String(getFromSet('markdown', '') || '').trim();
const baseText = String(getFromSet('message', getFromSet('cron_message', '提醒：请在 18:00 前提交今日工作日志。')));
const map = { link_title:linkTitle, link_url:linkUrl, date:dateStr, weekday:weekdayStr, random_emoji:rndEmoji, random_quote:rndQuote, random_tip:rndTip, base:baseText };
if (md) md = dedent(replacePlaceholders(md, map));
else md = [
  `#### ${rndEmoji} 日志提醒 · ${dateStr}（${weekdayStr}）`,
  `> ${rndQuote}`,
  `- ${baseText}`,
  `- 快捷入口： [${linkTitle}](${linkUrl})`,
  `> Tip：${rndTip}`
].join('\n\n');

md = ensureKeyword(md, required);

const payload = { msgtype:'markdown', markdown:{ title: mdTitle, text: md }, at:{ atMobiles, isAtAll: atAll } };
const signedWebhook = signUrl(baseWebhook, secret);
return [{ json: { dingtalk_webhook: signedWebhook, payload } }];
